proof_block:
// The two ensures-conjuncts both have shape `match ov { Some(e1) => ... e1@ ..., None => ... }`,
// but each binds its own `e1`, so the `match`/destructor triggers for r1 and r2 don't line up
// and z3 never chains `e1@ == r1@` with `e1@ == r2@`. Case-split on `ov` here to force both
// matches to expand together, then close with Seq extensionality.
match ov {
    Some(e1) => {
        assert(r1.is_some() && e1@ == r1.get_Some_0()@);
        assert(r2.is_some() && e1@ == r2.get_Some_0()@);
        assert(r1.get_Some_0()@ == r2.get_Some_0()@);
        assert(r1.get_Some_0()@ =~= r2.get_Some_0()@);
    }
    None => {
        assert(r1.is_None());
        assert(r2.is_None());
    }
}
